hooks.command:
python3 -c '
import json,os,re,subprocess,sys
try:
    if os.environ.get("PLAIN_ENGLISH_GATE"): sys.exit(0)
    d=json.load(sys.stdin)
    if d.get("stop_hook_active"): sys.exit(0)
    root=os.environ.get("CLAUDE_PROJECT_DIR") or "."
    guidance=open(root+"/.claude/communication.md").read()
    t=""
    for l in open(d.get("transcript_path") or "/dev/null"):
        try: r=json.loads(l)
        except Exception: continue
        if r.get("type")=="assistant":
            c=(r.get("message") or {}).get("content") or []
            x="".join(p.get("text","") for p in c if isinstance(p,dict) and p.get("type")=="text")
            if x.strip(): t=x
    if not t.strip(): sys.exit(0)
    p="Did this reply follow the communication guidance below? If it did NOT, reply '"'"'BLOCK: <what to fix>'"'"'. If it did, reply '"'"'OK'"'"'. Reply with nothing else.\n\n=== GUIDANCE ===\n"+guidance+"\n=== REPLY ===\n"+t[:6000]
    o=subprocess.run(["claude","-p",p],capture_output=True,text=True,timeout=45,env=dict(os.environ,PLAIN_ENGLISH_GATE="1")).stdout
    m=re.search(r"BLOCK:\s*([^\n]+)",o,re.I)
    if m: print(json.dumps({"decision":"block","reason":"Your last reply did not follow the communication guidance (.claude/communication.md): "+m.group(1).strip()+". Rewrite it accordingly."}))
except Exception:
    pass
'
